import { useState } from "react";

const Header = function ({ todos, filterTodos, setFilterTodos }) {
    const [filter, setFilter] = useState("");
    const handleFilterTodo = function (_status) {
        setFilter((status) => _status);
        setFilterTodos(todos.filter((todo) => todo.status === filter));
    };

    return (
        <>
            <header className="header">
                <h1>Todoアプリ</h1>
                <select value={filter} onChange={(e) => handleFilterTodo(e.target.value)}>
                    <option value="yet">未完了</option>
                    <option value="in-progress">進行中</option>
                    <option value="done">完了</option>
                </select>
            </header>
        </>
    );
};
export default Header;
